$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 45
$timeout = 600
$interval = 30
$elapsed = 0
$found = $false

while ($elapsed -lt $timeout) {
    # Strategy A: "Copilot's findings"
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.body != null) | {id: .id, body: .body, user: .user.login}' 2>$null
    if ($reviews) {
        foreach ($line in ($reviews -split "`n")) {
            if ($line -match "Copilot.s findings|Pull request overview|copilot-pull-request-reviewer") {
                Write-Output "FOUND REVIEW: $line"
                $found = $true
                break
            }
        }
    }
    if ($found) { break }

    # Strategy D: Line-level comments from Copilot
    $comments = gh api "/repos/$REPO/pulls/$PR/comments" --jq '.[] | select(.user.login == "Copilot" or (.user.login | test("copilot-pull-request-reviewer"))) | {id: .id, body: .body}' 2>$null
    if ($comments) {
        Write-Output "FOUND COMMENTS: $comments"
        $found = $true
        break
    }

    Write-Output "Poll $elapsed s - no review yet..."
    Start-Sleep -Seconds $interval
    $elapsed += $interval
}

if (-not $found) {
    Write-Output "TIMEOUT: No Copilot review found after $timeout seconds"
}

# Final dump of all reviews
Write-Output "--- ALL REVIEWS ---"
gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | {id: .id, user: .user.login, state: .state, body: (.body | if length > 200 then .[:200] + "..." else . end)}'
Write-Output "--- ALL COMMENTS ---"
