$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 45
$timeout = 600
$interval = 30
$elapsed = 0
$found = $false
$knownReviewIds = @(4729451923, 4729472298)

while ($elapsed -lt $timeout) {
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | {id: .id, body: (.body | if length > 200 then .[:200] + "..." else . end)}' 2>$null

    if ($reviews) {
        foreach ($line in ($reviews -split "`n")) {
            if ($line -match '"id":(\d+)') {
                $rid = [long]$Matches[1]
                if ($rid -notin $knownReviewIds) {
                    Write-Output "FOUND NEW REVIEW (id=$rid): $line"
                    $found = $true
                    break
                }
            }
        }
    }
    if ($found) { break }

    Write-Output "Poll $elapsed s - no new review yet..."
    Start-Sleep -Seconds $interval
    $elapsed += $interval
}

if (-not $found) {
    Write-Output "TIMEOUT: No new Copilot review after $timeout seconds"
} else {
    # Check comments count
    $newReview = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | select(.id != 4729451923 and .id != 4729472298) | .body'
    Write-Output "=== NEW REVIEW BODY ==="
    Write-Output $newReview
}

